import{_ as t,o as a,c as i,a2 as r}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"Privacy","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/privacy.md","filePath":"en/guide/privacy.md"}'),n={name:"en/guide/privacy.md"};function s(o,e,c,l,d,h){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h1><p>Nid includes tools to protect your privacy: tracking pixel detection, sensitive data scanner, and archive encryption.</p><hr><h2 id="tracking-pixel-detection" tabindex="-1">Tracking Pixel Detection <a class="header-anchor" href="#tracking-pixel-detection" aria-label="Permalink to &quot;Tracking Pixel Detection&quot;">​</a></h2><p>Many marketing emails contain <strong>tracking pixels</strong>: invisible images that notify the sender when you open the email.</p><h3 id="scan-your-emails" tabindex="-1">Scan Your Emails <a class="header-anchor" href="#scan-your-emails" aria-label="Permalink to &quot;Scan Your Emails&quot;">​</a></h3><ol><li>Open the <strong>Privacy</strong> page in the sidebar</li><li>In the <strong>Tracking pixels</strong> tab, click <strong>Scan</strong></li><li>A scan job is launched — it analyzes the HTML of your recent emails</li></ol><blockquote><p>📸 <em>Suggested screenshot: Tracking pixels tab with the Scan button and overall statistics</em></p></blockquote><h3 id="results" tabindex="-1">Results <a class="header-anchor" href="#results" aria-label="Permalink to &quot;Results&quot;">​</a></h3><p>After the scan, you can see:</p><ul><li><strong>Overall statistics</strong>: number of emails containing trackers, total number of trackers detected</li><li><strong>Per-email list</strong>: each email with the number and type of trackers detected</li><li><strong>Most frequent domains</strong>: ranking of tracking domains (e.g., Mailchimp, SendGrid, HubSpot)</li></ul><blockquote><p>📸 <em>Suggested screenshot: scan results with the list of emails containing trackers and detected domains</em></p></blockquote><h3 id="types-of-trackers-detected" tabindex="-1">Types of Trackers Detected <a class="header-anchor" href="#types-of-trackers-detected" aria-label="Permalink to &quot;Types of Trackers Detected&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>1×1 pixels</strong></td><td>Invisible images (1 pixel) loaded when the email is opened</td></tr><tr><td><strong>Known domains</strong></td><td>Over 35 identified email marketing domains (Mailchimp, SendGrid, HubSpot, Klaviyo, Brevo, etc.)</td></tr><tr><td><strong>UTM parameters</strong></td><td>Links containing tracking parameters (utm_source, utm_medium, utm_campaign)</td></tr></tbody></table><hr><h2 id="sensitive-data-scanner-pii" tabindex="-1">Sensitive Data Scanner (PII) <a class="header-anchor" href="#sensitive-data-scanner-pii" aria-label="Permalink to &quot;Sensitive Data Scanner (PII)&quot;">​</a></h2><p>The PII (Personally Identifiable Information) scanner analyzes your archived emails to detect sensitive data in plain text.</p><h3 id="scan-your-archives" tabindex="-1">Scan Your Archives <a class="header-anchor" href="#scan-your-archives" aria-label="Permalink to &quot;Scan Your Archives&quot;">​</a></h3><ol><li>In the <strong>Sensitive data</strong> tab, click <strong>Scan</strong></li><li>A scan job analyzes the EML files in your archives</li></ol><blockquote><p>📸 <em>Suggested screenshot: Sensitive data tab with the Scan button</em></p></blockquote><h3 id="types-of-data-detected" tabindex="-1">Types of Data Detected <a class="header-anchor" href="#types-of-data-detected" aria-label="Permalink to &quot;Types of Data Detected&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Example</th></tr></thead><tbody><tr><td><strong>Credit card</strong></td><td>Visa, Mastercard, Amex (with separators)</td></tr><tr><td><strong>IBAN</strong></td><td>International bank account number</td></tr><tr><td><strong>Social security number</strong></td><td>French social security number</td></tr><tr><td><strong>Plaintext password</strong></td><td>Text containing &quot;password:&quot;, &quot;pwd=&quot;, etc.</td></tr><tr><td><strong>Phone number</strong></td><td>French number (+33, 06, 07...)</td></tr></tbody></table><blockquote><p>📸 <em>Suggested screenshot: PII scan results with data type, number of affected emails, and a masked snippet</em></p></blockquote><div class="info custom-block"><p class="custom-block-title">Masked data</p><p>Excerpts shown in the results are automatically masked (e.g., <code>****-****-****-4242</code>) to avoid exposing actual data in the interface.</p></div><hr><h2 id="archive-encryption" tabindex="-1">Archive Encryption <a class="header-anchor" href="#archive-encryption" aria-label="Permalink to &quot;Archive Encryption&quot;">​</a></h2><p>Your EML archives can be encrypted on the NAS using <strong>AES-256-GCM</strong> encryption (the same standard used by banks and governments).</p><h3 id="configure-encryption" tabindex="-1">Configure Encryption <a class="header-anchor" href="#configure-encryption" aria-label="Permalink to &quot;Configure Encryption&quot;">​</a></h3><ol><li>In the <strong>Encryption</strong> tab, click <strong>Configure</strong></li><li>Choose a <strong>passphrase</strong></li><li>Confirm the passphrase</li><li>Click <strong>Enable encryption</strong></li></ol><blockquote><p>📸 <em>Suggested screenshot: encryption configuration form with the passphrase field</em></p></blockquote><div class="warning custom-block"><p class="custom-block-title">Keep your passphrase safe</p><p>The passphrase is <strong>never stored</strong> in the application — only a verification hash is kept. If you lose it, it will be impossible to decrypt your archives. Write it down in a safe place (password manager, etc.).</p></div><h3 id="encrypt-existing-archives" tabindex="-1">Encrypt Existing Archives <a class="header-anchor" href="#encrypt-existing-archives" aria-label="Permalink to &quot;Encrypt Existing Archives&quot;">​</a></h3><p>After configuring the passphrase:</p><ol><li>Click <strong>Encrypt archives</strong></li><li>An encryption job is launched</li><li>Each EML file is individually encrypted on disk</li></ol><p>Already encrypted emails are automatically skipped (idempotent).</p><h3 id="read-an-encrypted-email" tabindex="-1">Read an Encrypted Email <a class="header-anchor" href="#read-an-encrypted-email" aria-label="Permalink to &quot;Read an Encrypted Email&quot;">​</a></h3><p>When you view an encrypted email on the Archives page, it is <strong>decrypted on the fly</strong> in server memory. The file remains encrypted on disk at all times.</p><h3 id="encryption-status" tabindex="-1">Encryption Status <a class="header-anchor" href="#encryption-status" aria-label="Permalink to &quot;Encryption Status&quot;">​</a></h3><p>The Encryption tab displays:</p><ul><li>Whether a passphrase is configured</li><li>The number of encrypted / unencrypted emails</li><li>An overall security indicator</li></ul><blockquote><p>📸 <em>Suggested screenshot: encryption status with the number of encrypted emails and percentage</em></p></blockquote>',41)])])}const g=t(n,[["render",s]]);export{u as __pageData,g as default};
